package com.infy.inventrack.inventory.controller; import com.infy.inventrack.common.dto.*; import com.infy.inventrack.inventory.service.InventoryService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.List; @RestController @RequestMapping("/inventory") public class InventoryController { private final InventoryService service; public InventoryController(InventoryService s){service=s;} @GetMapping("/{sku}") public ResponseEntity<InventoryResponse> get(@PathVariable String sku,@RequestHeader(value=HttpHeaders.AUTHORIZATION,required=false) String auth){return ResponseEntity.ok(service.getStockBySku(sku,auth));} @PostMapping("/{sku}/reserve") public ResponseEntity<String> reserve(@PathVariable String sku,@Valid @RequestBody ReserveStockRequest r,@RequestHeader(value=HttpHeaders.AUTHORIZATION,required=false) String auth){return ResponseEntity.ok(service.reserveStock(sku,r.getQuantity(),auth));} @GetMapping("/value") public ResponseEntity<Double> value(){return ResponseEntity.ok(service.calculateTotalInventoryValue());} @GetMapping("/low-stock") public ResponseEntity<List<InventoryResponse>> low(@RequestParam Integer threshold){return ResponseEntity.ok(service.findLowStockProducts(threshold));} }
